// Extraer datos del mensaje de Telegram
const mensaje = $input.item.json.message;

const datosCliente = {
  chatId: mensaje.chat.id,
  nombreCliente: mensaje.from.first_name + ' ' + (mensaje.from.last_name || ''),
  username: mensaje.from.username || 'Sin username',
  mensaje: mensaje.text || '',
  fecha: new Date().toLocaleString('es-ES'),
  timestamp: new Date().toISOString()
};

console.log('📩 Mensaje recibido de:', datosCliente.nombreCliente);
console.log('💬 Contenido:', datosCliente.mensaje);

return { json: datosCliente };

// Parsear clasificación del LLM
const aiResponse = $input.item.json;
const datosCliente = $('Preparar datos').item.json;

let intencion = 'CONSULTA'; // Default

try {
  let responseText = '';

  // Extraer texto de diferentes formatos posibles
  if (typeof aiResponse.output === 'string') {
    responseText = aiResponse.output;
  } else if (typeof aiResponse === 'string') {
    responseText = aiResponse;
  } else if (aiResponse.text) {
    responseText = aiResponse.text;
  } else {
    responseText = JSON.stringify(aiResponse);
  }

  // Limpiar markdown
  const cleanText = responseText
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  // Buscar JSON
  const jsonMatch = cleanText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    intencion = parsed.intencion || 'CONSULTA';
  } else {
    // Buscar palabras clave si no hay JSON
    if (cleanText.includes('COMPRA')) intencion = 'COMPRA';
    else if (cleanText.includes('SOPORTE')) intencion = 'SOPORTE';
    else intencion = 'CONSULTA';
  }

} catch (error) {
  console.log('⚠️ Error parseando:', error.message);
  intencion = 'CONSULTA';
}

console.log('🎯 Intención clasificada:', intencion);

return {
  json: {
    ...datosCliente,
    intencion: intencion,
    clasificacionRaw: aiResponse
  }
};

// Formatear respuesta de COMPRA
const aiResponse = $input.item.json;
const datosCliente = $('Parsear clasificación').item.json;

let respuestaGenerada = '';

if (typeof aiResponse.output === 'string') {
  respuestaGenerada = aiResponse.output.trim();
} else if (typeof aiResponse === 'string') {
  respuestaGenerada = aiResponse.trim();
} else if (aiResponse.text) {
  respuestaGenerada = aiResponse.text.trim();
} else {
  respuestaGenerada = 'Gracias por tu interés. Un asesor te contactará pronto.';
}

console.log('✅ Respuesta generada (COMPRA):', respuestaGenerada.substring(0, 50) + '...');

return {
  json: {
    ...datosCliente,
    respuestaGenerada: respuestaGenerada,
    tipoRespuesta: 'COMPRA',
    notificarVentas: true
  }
};

// Formatear respuesta de CONSULTA/SOPORTE
const aiResponse = $input.item.json;
const datosCliente = $('Parsear clasificación').item.json;

let respuestaGenerada = '';

if (typeof aiResponse.output === 'string') {
  respuestaGenerada = aiResponse.output.trim();
} else if (typeof aiResponse === 'string') {
  respuestaGenerada = aiResponse.trim();
} else if (aiResponse.text) {
  respuestaGenerada = aiResponse.text.trim();
} else {
  respuestaGenerada = 'Gracias por contactarnos. ¿En qué más puedo ayudarte?';
}

console.log('✅ Respuesta generada (CONSULTA/SOPORTE):', respuestaGenerada.substring(0, 50) + '...');

return {
  json: {
    ...datosCliente,
    respuestaGenerada: respuestaGenerada,
    tipoRespuesta: datosCliente.intencion,
    notificarVentas: false
  }
};
